using UnityEngine;
using UnityEngine.UI;
using System;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int damage = 10;

    public event Action<int, int> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnDamageChanged;

    private void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        NotifyAll();
    }

    public void TakeDamage(int amount)
    {
        if (amount <= 0) return;
        currentHealth = Mathf.Max(0, currentHealth - amount);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        currentHealth = Mathf.Min(maxHealth, currentHealth + amount);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public void AddCurrency(int amount)
    {
        if (amount <= 0) return;
        currency += amount;
        OnCurrencyChanged?.Invoke(currency);
    }

    public bool SpendCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (currency < amount) return false;
        currency -= amount;
        OnCurrencyChanged?.Invoke(currency);
        return true;
    }

    public void IncreaseDamage(int amount)
    {
        if (amount <= 0) return;
        damage += amount;
        OnDamageChanged?.Invoke(damage);
    }

    public void SetDamage(int value)
    {
        damage = Mathf.Max(0, value);
        OnDamageChanged?.Invoke(damage);
    }

    public void SetMaxHealth(int value)
    {
        maxHealth = Mathf.Max(1, value);
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    private void NotifyAll()
    {
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        OnCurrencyChanged?.Invoke(currency);
        OnDamageChanged?.Invoke(damage);
    }
}

[Serializable]
public class ShopItem
{
    public string itemId;
    public string displayName;
    public int basePrice = 100;
    public int priceMultiplier = 1;
    public int damageBonus = 0;
    public int healthBonus = 0;
    public int currencyBonus = 0;

    public int GetPrice()
    {
        return Mathf.Max(0, basePrice * Mathf.Max(1, priceMultiplier));
    }

    public int GetDamageValue()
    {
        return Mathf.Max(0, damageBonus);
    }

    public int GetHealthValue()
    {
        return Mathf.Max(0, healthBonus);
    }

    public int GetCurrencyValue()
    {
        return Mathf.Max(0, currencyBonus);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItem[] items;

    public bool PurchaseItem(int index)
    {
        if (playerStats == null) return false;
        if (items == null || index < 0 || index >= items.Length) return false;

        ShopItem item = items[index];
        int price = item.GetPrice();

        if (!playerStats.SpendCurrency(price))
            return false;

        if (item.damageBonus > 0)
            playerStats.IncreaseDamage(item.GetDamageValue());

        if (item.healthBonus > 0)
            playerStats.SetMaxHealth(playerStats.maxHealth + item.GetHealthValue());

        if (item.currencyBonus > 0)
            playerStats.AddCurrency(item.GetCurrencyValue());

        return true;
    }

    public int GetItemPrice(int index)
    {
        if (items == null || index < 0 || index >= items.Length) return 0;
        return items[index].GetPrice();
    }

    public int GetItemDamage(int index)
    {
        if (items == null || index < 0 || index >= items.Length) return 0;
        return items[index].GetDamageValue();
    }
}

public class DamageCalculator : MonoBehaviour
{
    public PlayerStats playerStats;

    public int CalculateDamage(int baseDamage, float multiplier, int bonus)
    {
        int playerDamage = playerStats != null ? playerStats.damage : 0;
        float raw = (baseDamage + playerDamage + bonus) * multiplier;
        return Mathf.Max(0, Mathf.RoundToInt(raw));
    }

    public void DealDamageToTarget(PlayerStats target, int baseDamage, float multiplier, int bonus)
    {
        if (target == null) return;
        int finalDamage = CalculateDamage(baseDamage, multiplier, bonus);
        target.TakeDamage(finalDamage);
    }
}

public class SimpleUI : MonoBehaviour
{
    public PlayerStats playerStats;
    public Text healthText;
    public Text currencyText;
    public Text damageText;

    private void OnEnable()
    {
        if (playerStats == null) return;
        playerStats.OnHealthChanged += HandleHealthChanged;
        playerStats.OnCurrencyChanged += HandleCurrencyChanged;
        playerStats.OnDamageChanged += HandleDamageChanged;
        Refresh();
    }

    private void OnDisable()
    {
        if (playerStats == null) return;
        playerStats.OnHealthChanged -= HandleHealthChanged;
        playerStats.OnCurrencyChanged -= HandleCurrencyChanged;
        playerStats.OnDamageChanged -= HandleDamageChanged;
    }

    private void HandleHealthChanged(int current, int max)
    {
        if (healthText != null) healthText.text = current + "/" + max;
    }

    private void HandleCurrencyChanged(int value)
    {
        if (currencyText != null) currencyText.text = value.ToString();
    }

    private void HandleDamageChanged(int value)
    {
        if (damageText != null) damageText.text = value.ToString();
    }

    private void Refresh()
    {
        if (playerStats == null) return;
        HandleHealthChanged(playerStats.currentHealth, playerStats.maxHealth);
        HandleCurrencyChanged(playerStats.currency);
        HandleDamageChanged(playerStats.damage);
    }
}